-- Mentees: HJG's internal SOURCE OF TRUTH for each person, mirrored from the
-- Notion 'Mentees Database'. One row per mentee. `client_id` soft-refs
-- ca_clients.id (null for prospects not yet in CoachAccountable). All 19 Notion
-- columns are mirrored (Notion page-link URLs stripped from text values).
--
-- HJG-owned, staff-RLS (same shape as mentee_outcomes). The dashboard edits this
-- table going forward; this seed is a ONE-TIME import that won't clobber edits
-- (insert ... on conflict (notion_key) do nothing). Apply via the Supabase SQL
-- Editor; re-runnable. Depends on set_updated_at() from 9999_init.

create table if not exists mentees (
  id            uuid primary key default gen_random_uuid(),
  client_id     bigint,                      -- soft ref to ca_clients.id (null = not in CA)
  notion_key    text not null,               -- normalized name; idempotency key for the seed
  name          text not null,               -- Notion 'Mentees Paired'
  wants_pp      text,
  mentor_1      text,
  status        text,                         -- Notion pipeline status
  mt_prayer_partner text,
  projected_start   date,
  associated_tasks  text,
  current_invoice_amount numeric(12,2),
  ff_amount         numeric(12,2),
  freedom_fight_paid text,
  js_lesson         text,
  mn_equivalency    numeric(12,2),
  mentor            text,
  offering_signup   date,
  dd_w_a            numeric(12,2),
  dc_date           date,
  email             text,
  date_ff_paid      date,
  phone             text,
  created_by    uuid references auth.users (id),
  created_at    timestamptz not null default now(),
  updated_at    timestamptz not null default now()
);
create unique index if not exists uq_mentees_notion_key on mentees (notion_key);
-- One source-of-truth row per CA client; null client_id (prospects not yet in CA)
-- is unconstrained. This partial unique index also serves non-null client_id lookups.
create unique index if not exists uq_mentees_client on mentees (client_id) where client_id is not null;
drop trigger if exists trg_mentees_updated on mentees;
create trigger trg_mentees_updated before update on mentees
  for each row execute function set_updated_at();

-- RLS: signed-in staff read everything and read/write (same shape as the other
-- HJG-owned tables). drop-if-exists keeps this re-runnable.
alter table mentees enable row level security;
drop policy if exists mentees_read on mentees;
create policy mentees_read on mentees for select to authenticated using (true);
drop policy if exists mentees_ins on mentees;
create policy mentees_ins  on mentees for insert to authenticated with check (true);
drop policy if exists mentees_upd on mentees;
create policy mentees_upd  on mentees for update to authenticated using (true);
drop policy if exists mentees_del on mentees;
create policy mentees_del  on mentees for delete to authenticated using (created_by = auth.uid());

-- One-time seed from the Notion export (2026-06-24). Re-running is a no-op for
-- rows that already exist, so it never overwrites later dashboard edits.
-- Seeded rows intentionally have created_by = null (no owner), so the
-- created_by-scoped delete policy won't let staff delete imported rows from the UI
-- (same pattern as mentee_outcomes); they stay editable via the update policy.
on conflict (notion_key) do nothing;

